var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......저보고 아카데미 운동회에 선수로 나가라는 말씀이신가요?","JPN":"……私にアカデミー運動会の選手として出場してほしいということですか？","ENG":"... You want me to join the Academy Field Day as a player?","TWN":"……您是說讓我以選手身份參加學院運動會嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇습니다. 고양이도 쥐를 잡을 때는 최선을 다하는 법이니까요.","JPN":"そうです。猫がネズミ狩りをする時も最善を尽くすものですから。","ENG":"That's right. A cat will use all of her strength even when hunting a rat.","TWN":"是的，因為貓在抓老鼠時也會竭盡全力。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"호랑이가 토끼를 잡을 때가 아니라요?","JPN":"獅子がウサギ狩りをする時ではなくて？","ENG":"You mean, a lioness when hunting a rabbit.","TWN":"不是老虎抓兔子嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"흥, 호랑이는 무슨.","JPN":"ふん、獅子ですって？","ENG":"Hah, nonsense.","TWN":"哼，老虎個鬼。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양에게는 도둑고양이 정도가 딱 어울립니다.","JPN":"シズカさんには野良猫程度が相応しいでしょう。","ENG":"You're a stray cat at best, Seo Yoon.","TWN":"野貓這個稱呼最適合你了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장님, 혹시 입사 면접 때 일로 아직 토라져 계신 거 아니죠?","JPN":"副社長、もしかして入社面接の日のことでまだ拗ねているんですか？","ENG":"Vice President, you're not still upset because of what I said during my job interview, are you?","TWN":"副總，您不會是因為入職面試的事還在鬧脾氣吧？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무슨 소린지 모르겠네요. 전 공과 사를 아주 잘 구별하는 사람입니다.","JPN":"なんのことなのかわかりませんね。私は公私をしっかり分ける人間ですよ。","ENG":"I don't know what you're talking about. I never let my personal feelings interfere with business.","TWN":"不知道你在說什麼，我可是個公私分明的人。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"글쎄요? 저는 잘 모르겠는데......?","JPN":"そうですか？　私にはよくわかりませんが……？","ENG":"Well, I'm not so sure about that...","TWN":"是嗎？我還真不知道……？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쨌든 서윤 양이라면 경험도 부족한 풋내기 카운터들을 상대로 우승하는 건 아주 쉬운 일이겠죠.","JPN":"とにかく、シズカさんなら経験不足の青二才カウンター相手に優勝するのは簡単なことでしょう。","ENG":"Anyway, Seo Yoon, I believe it will be an easy task for you to achieve victory against those inexperienced Counters.","TWN":"總之，對於你來說，對付幾個經驗不足的新手制裁者奪得第一名應該不難吧。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 운동회에서 우승을 하고 그 <color=#ffd34c>소원구슬</color>이란 걸 가지고 와야 합니다.","JPN":"ですので運動会で優勝して、その<color=#ffd34c>願い玉</color>という物を持ってきてください。","ENG":"I want you to win the Field Day and bring back the prize called the <color=#ffd34c>Wishing Ball</color>.","TWN":"所以，你必須在運動會上奪冠，並拿回那個叫<color=#ffd34c>許願珠</color>的東西。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>어떤 소원이든 하나를 이뤄주는 구슬</color>이라......","JPN":"<color=#ffd34c>どんな願いでも叶えてくれる玉</color>だなんて……","ENG":"A <color=#ffd34c>ball that grants any single wish</color>, huh.","TWN":"<color=#ffd34c>可以實現願望的珠子</color>……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장님이 그런 동화 같은 이야기를 믿으시다니. 의외로 순수한 면도 있으셨네요.","JPN":"そんなおとぎ話を信じるなんて、副社長も意外とピュアな面があったのですね。","ENG":"You believe in this fairy tale? I didn't know you were so naive.","TWN":"副總居然相信那種虛無縹緲的事情，沒想到您還有這麼單純的一面。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론 저 역시 정말로 모든 소원을 들어주는 아티팩트가 존재한다고 믿지는 않습니다.","JPN":"もちろん私も本当に願いを叶えてくれる\\nアーティファクトが存在すると信じているわけではありません。","ENG":"Of course I don't believe there is an Artifact that can grant people's wishes.","TWN":"我當然不相信真的有可以實現所有願望的人造神器。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 그런 이름이 붙을 정도라면, 적어도 강력한 힘을 가진 물건일 가능성이 크겠죠.","JPN":"しかしそのような名前が付くのであれば、\\n少なくとも何かしら強大な力を持っている物である可能性が高いです。","ENG":"But it's got to be powerful enough to be called that.","TWN":"不過既然叫了那種名字，很有可能是蘊含強大力量的東西吧。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확보한다면 회사 재정에도 큰 도움이 될 겁니다.","JPN":"確保しておけば、会社の財政にも大いに役立つでしょう。","ENG":"If we can get our hands on it, it'll greatly help us with our financial situation.","TWN":"而且對公司財政應該也是一大助力。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"후훗. 알겠어요. 저야 시키면 시키는 대로 해야죠.","JPN":"ふふ、わかりました。まあ、私に選択肢はないですけどね。","ENG":"Hah hah. Okay, I'll do as you say.","TWN":"呼呼，知道了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데 아카데미라면 조만간 미나가 편입하기로 예정된 곳 아닌가요?","JPN":"ところでアカデミーって、ミナが編入する学校ですよね？","ENG":"But Mina is supposed to transfer to the Academy soon.","TWN":"說起學院，米娜不是要去那裡插班嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 미나에게 임무를 맡기는 게 더 자연스러울 텐데요.","JPN":"それならミナに任務を任せるのが自然だと思いますが。","ENG":"Wouldn't it be more natural for her to carry out the mission?","TWN":"那直接把任務交給米娜去做應該更好吧。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양의 실력도 나쁘지는 않지만, 정신적으로는 좀 물렁한 구석이 있죠.","JPN":"ミナさんの実力も悪くありませんが、精神的な面で多少甘いところがありまして。","ENG":"Mina is good enough, but she's a bit soft mentally.","TWN":"雖然米娜的實力也不差，但性格有些柔和。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 부분에서만큼은 서윤 양을 확실하게 믿고 있습니다.","JPN":"そういう面ではシズカさんのほうが適任でしょう。","ENG":"I know I can trust you with this kind of work.","TWN":"在這方面，我更相信你。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어떤 사악하고 비열한 방법을 써서라도 반드시 아티팩트를 확보해 올 거라고 말입니다.","JPN":"どんなに邪悪で卑劣な方法を使ってでも、必ずアーティファクトを確保してくると信じています。","ENG":"You will retrieve the Artifact no matter what, by using every evil and despicable means you can think of.","TWN":"我相信你一定會無所不用其極的拿到人造神器。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇지 않나요?","JPN":"そうではありませんか？","ENG":"Am I not right?","TWN":"不是嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"확실히 경영을 하시는 분답게 사람 보는 눈이 뛰어나시네요.","JPN":"経営者らしく、確かに人を見る目がありますね。","ENG":"You have an eye for people, like the good businesswoman you are.","TWN":"不愧是管理者，您看人的眼光可真準。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"뭐, 부사장님께서 그렇게 기대를 걸어주신다면야......","JPN":"まあ、副社長がそこまで言って期待しているなら……","ENG":"Well, if you have so much trust in me, then...","TWN":"既然副總您對我這麼有信心……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"조금 힘을 써 봐야겠는걸요?","JPN":"ちょっと本気を出してみましょうか？","ENG":"I'll see what I can do.","TWN":"我要再加把勁兒才行呢。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......잘 처리했네.","JPN":"……よくやってくれた。","ENG":"... Good job.","TWN":"……處理得很好。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"소원 구슬 같은 강력한 아티팩트가 잘못된 주인의 손에 들어가선 곤란해.","JPN":"願い玉のような強力なアーティファクトが相応しくない持ち主の手に渡ってしまっては困る。","ENG":"We can't let powerful Artifacts like that Wishing Ball fall into the wrong hands.","TWN":"像許願珠這麼強大的人造神器，落入壞人之手就麻煩了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 이쪽에서 먼저 수거하는 편이 좋겠지.","JPN":"だからこちらで先に回収したほうがいいだろう。","ENG":"It'd be best to have it in our possession beforehand.","TWN":"所以，還是我們先收回來比較好。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그걸 아는 사람이 물건을 유적에 그대로 두고 왔습니까?","JPN":"……それをわかっている人があんな大事なものを遺跡に置いてきたのですか？","ENG":"If you knew that, why did you leave it in the ruins?","TWN":"……知道這個的人怎麼還把東西留在遺跡裡了？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이상한 보증서까지 써 놓고?","JPN":"変な保証書まで添えて？","ENG":"With that ridiculous certificate, to boot?","TWN":"還寫了奇怪的保證書？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그, 그건 신비의 탐험가 <color=#ffd34c>인디애나 GAP</color>이 벌인 짓이라니까. 난 전혀 모르는 일일세.","JPN":"あ、あれは神秘の探検家<color=#ffd34c>インディアナ-甲-</color>がやらかしたことだ。私は全く関係ない。","ENG":"I-it was <color=#ffd34c>Indiana G.A.P.</color> the mysterious explorer who did that. I had nothing to do with it.","TWN":"都，都說了那是神秘探險家<color=#ffd34c>印第安納GAP</color>做的，我完全不知情。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아마 그 친구도 뭔가 사정이 있어서 그랬겠지.","JPN":"おそらくその人も何らかの事情があったのだろう。","ENG":"He had to have a reason, though.","TWN":"他那麼做應該也是有原因的。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"발굴 성과를 바짝 쫓아오는 건방진 라이벌에게 자신과의 격차를 보여 주고 싶었다거나......","JPN":"発掘成果を追いかけてくる生意気なライバルに自分との差を見せつけたかったとか……","ENG":"To prove his superiority over his arrogant competitor, who was just a few steps behind him in the field, for example...","TWN":"也許是想要給那些只會一味追求成果的傲慢對手一個下馬威……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시끄러워요.","JPN":"ダサい言い訳はその辺にしておきましょう。","ENG":"Shut it.","TWN":"吵死了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠...... 평소에는 잘만 보관하더니 무슨 바람이 불었는지 참......","JPN":"こほん……いつもならしっかり保管する人がどういう風の吹き回しで……まったく……","ENG":"Kahem... She usually keeps the Artifacts to herself. I don't know what got into her this time...","TWN":"咳嗯……我一直很小心保管，那時不知怎麼……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 됐습니다. 이 기회에 희귀 아티팩트를 손에 넣어서 나쁠 건 없겠죠.","JPN":"まあ、いいでしょう。この機会に希少アーティファクトを入手しておくのもいいと思います。","ENG":"Well, forget it. We might as well take this opportunity to get hold of a rare Artifact.","TWN":"唉，算了。借這個機會，把稀有人造神器弄到手也不錯。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"최근 회사 사정이 나아지고 있긴 해도, 현금성 자산은 많을수록 좋으니까요.","JPN":"最近少しマシになってきたとはいえ、現金に変えられる資産は多いに越したことがありませんので。","ENG":"Even though our company is doing better than before, it's always good to have assets that can be readily converted to cash.","TWN":"雖然最近公司情況有所好轉，但現金資產自然是越多越好。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 말이네만......","JPN":"それなんだが……","ENG":"Now that you mention that...","TWN":"的確如此……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"확실하게 아티팩트를 수거하려면 조력자가 따라가는 편이 좋지 않겠나?","JPN":"確実にアーティファクトを入手するためには助っ人がついて行ったほうがいいのでは？","ENG":"How about we send someone with Seo Yoon to ensure we get the Artifact?","TWN":"所以，為了確保拿到人造神器，帶個幫手是不是更好？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"불필요한 변수를 차단할 수 있을 만큼 믿음직스러운 친구로 말이야.","JPN":"余計な要因を遮断できるほど頼もしい人でね。","ENG":"Someone reliable, who can eliminate all the unnecessary variables.","TWN":"再派一個靠得住的人以防不測嘛。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......또 누굴 보내서 무슨 사고를 치시려고?","JPN":"……また誰かを送りつけてトラブルを起こすつもりですか？","ENG":"Which troublemaker are you talking about?","TWN":"……你又想派誰去惹什麼麻煩？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"사고라니. 부사장님도 너무하네.","JPN":"トラブル？　副社長、それは言いすぎだわ。","ENG":"Troublemaker? That's not nice, Vice President.","TWN":"什麼叫惹麻煩啊，副總您這話過分了啊。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"그렇게 말하면 내가 항상 문제만 일으키고 다니는 것 같잖아.","JPN":"そんな言い方だと、私がいつも問題ばかり起こしているように聞こえるじゃない。","ENG":"You make it sound as if I always cause trouble.","TWN":"說得好像我一直在製造麻煩似的。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마 이 녀석을 보낼 생각이신가요?","JPN":"まさか、こいつを行かせるつもりですか？","ENG":"You're not thinking of sending her, are you?","TWN":"你不會是想派這傢伙去吧？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그...... 요즘 들어 바깥 나들이를 하고 싶다고 고집을 피워서 말이야.","JPN":"まあ……最近外に出たいと駄々をこねてきてな。","ENG":"Erm... She's been insisting that she wants to go see the outside world.","TWN":"那個……她最近一直吵著要出去。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"서윤 양에게 보호자가 한 명 동행한다면 위장 편입도 좀 더 그럴싸해 보이지 않겠나?","JPN":"シズカ君に保護者が一人同行すれば、偽装編入がさらにそれっぽく見えると思わないか？","ENG":"Seo Yoon's disguised entry into the Academy will be more believable if she is accompanied by a chaperone. Don't you think?","TWN":"有個監護人陪你去的話，也更好偽裝不是嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......그래서 제 임무에 낙하산으로 내려오셨다는 거네요.","JPN":"……それで私の任務に無理やり加えたということですね。","ENG":"So, the higher-ups sent you here to join me on this mission?","TWN":"……也就是說，你空降到我的任務裡了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저번 파티 때도 그렇고 사장님이랑 꽤 친하신가 보네요?","JPN":"前のパーティーの時もそうですし、社長とかなり仲が良いみたいですね？","ENG":"Considering what happened before at the party, you must be pretty close to the Boss.","TWN":"上次開派對的時候也是，看來你跟老闆關係很好啊？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아. ","JPN":"お・","ENG":"A. U. ","TWN":"大。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"줌. ","JPN":"ば・","ENG":"N. T. ","TWN":"嬸。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"마.","JPN":"さん。","ENG":"I. E.","TWN":"好。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗, 아줌마 대신 언니라고 불러 주진 않으려나?","JPN":"フフッ、おばさんじゃなくてお姉ちゃんって呼んでくれないかしら？","ENG":"Hah hah. I prefer you call me Alex.","TWN":"嗯呵~，別叫大嬸，看顏質也知道該叫姐姐好不好？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"아, 혹시 질투하는 거야? 귀여워라.","JPN":"あら、もしかして嫉妬しているの？　まあ可愛い。","ENG":"Wait, are you jealous of me? How cute!","TWN":"啊，難道是在嫉妒我？真可愛。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"듣자하니 부사장님과 비슷한 연배라고 하시는 것 같던데요.","JPN":"噂だと、副社長と同世代と聞いていますが。","ENG":"I've heard you're the similiar age as the Vice President.","TWN":"我聽說你跟副總是同輩。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"연령대를 고려하면 아줌마라는 것도 아주 너그러운 표현 아닐까요?","JPN":"その歳を考えるとおばさんという呼び方すら寛大すぎると思いませんか？","ENG":"Even calling you auntie is way too generous, in my opinion.","TWN":"考慮到您的年紀，叫大嬸已經叫年輕了，不是嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그래서 더 충실하게 살려고 노력 중이야. 후회할 일 없게.","JPN":"だからもっと充実した生き方をしようと頑張っているの。後悔しないようにね。","ENG":"That's why I'm trying to make the best of my life, so I won't have any regrets.","TWN":"所以，我努力要過得更充實，免得將來後悔。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그나저나 신기하네.","JPN":"でも不思議だわ。","ENG":"By the way, don't you think this is amazing?","TWN":"不過真神奇啊。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"바다가 뭔진 알고 있었지만 유람선을 타거나 운동회에 와 보는 건 처음이야.","JPN":"海が何かは知っていたけど、クルーズに乗ったり運動会に来るのは初めてなの。","ENG":"I knew what the sea was, but I've never been on a cruise or on a Field Day.","TWN":"我雖然知道大海是什麼，但還是第一次坐遊船，第一次參加運動會呢。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"학교 운동회라는 건 전부 이렇게 으리으리해?","JPN":"学校の運動会というのは、全部こんなに立派な行事なの？","ENG":"Is the Field Day always this glitzy?","TWN":"學校運動會全都這麼壯觀嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"글쎄요? 아마 세계 최고의 휴양지 섬에서 운동회를 여는 건 아카데미뿐이지 않을까요?","JPN":"さあ？　世界最高のリゾート地の島で運動会を開くのはおそらくアカデミーしかないと思いますよ？","ENG":"I doubt it. Only the Academy can afford to throw a Field Day on the world's greatest resort island.","TWN":"這個嘛，估計也就只有學院會在全世界最好的度假島上開運動會吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"제가 다니던 학교에는 운동회가 없어서 잘 모르겠지만 말이죠.","JPN":"私が通っていた学校には運動会なんてなかったのでよくわかりませんが。","ENG":"But what do I know? The school I went to had no Field Days.","TWN":"我就讀的學校沒有運動會，所以不太清楚。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그럼 우리 둘 다 운동회에 대해선 초보인 셈이네?","JPN":"それじゃあ、私たちは二人とも運動会に関しては初心者なのね？","ENG":"Then we're both new, aren't we?","TWN":"那也就是說我們兩個都算是運動會新手呢。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"같이 열심히 해 보자.","JPN":"一緒に頑張ろうね。","ENG":"Let's make the best of the day.","TWN":"我們一起加油吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저는 신경 쓰지 말고 편하게 즐기세요.","JPN":"私は気にしなくていいので、好きに楽しんでくださいね。","ENG":"Don't mind me and enjoy yourself.","TWN":"別管我，你玩得開心就好。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"보호자 역할로 왔다고는 하지만, 알렉스 씨는 그냥 놀러 나오고 싶었던 거잖아요?","JPN":"保護者役で来るのは口実で、アレックスさんはただ遊びに来たかっただけでしょう？","ENG":"You're here as my chaperone, but it's just an excuse for you to be out in the world.","TWN":"雖然你名義上是我的監護人，但實際上你不是為了玩才出來的嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후후, 애들은 엄마가 간섭하는 거 싫어한다더니 딱 들은 대로네.","JPN":"フフ、子どもはお母さんに口出しされるのが嫌いって聞いていたけど、そのとおりね。","ENG":"Hah hah, just as I heard. Kids don't like it when their moms interfere with their lives.","TWN":"呼呼，都說孩子們討厭媽媽干涉，這話果然不假呢。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"걱정 마. 친구들 앞에서 아는 척하진 않을 테니까.","JPN":"心配しなくていいのよ。お友達の前ではちゃんと知らないふりをするから。","ENG":"Don't worry. I won't talk to you when you're with your friends.","TWN":"別擔心，在朋友們面前，我會裝作不認識你的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"대신 점심 시간엔 굶지 말고 내가 가져온 도시락 꼭 챙겨 먹기. 알겠지?","JPN":"かわりにお昼ご飯は私が作ったお弁当をちゃんと食べること、わかったわね？","ENG":"But don't skip your meals. Eat the lunch I brought for you, okay?","TWN":"不過午飯一定要按時吃，我帶給你的便當別忘了。知道了吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......글쎄요. 전 입맛이 까다로운 편이라서요.","JPN":"……どうでしょうね。私、味にはうるさいので。","ENG":"Well, I can't promise you that. I'm a picky eater.","TWN":"……這個嘛，我的口味比較挑剔。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};